mapper.select:
SELECT p.ID AS id, p.CODE AS code, p.NAME AS name, p.TYPE AS type, p.TICKET_CODE_TYPE AS ticketCodeType, p.MANAGER_NAME AS managerName, p.STATUS AS status, p.CONTRACT_START_DATE AS contractStartDate, p.CONTRACT_END_DATE AS contractEndDate, p.COMMISSION_RATE AS commissionRate, p.VISIBLE AS visible FROM PARTNERS p WHERE 1=1
AND ( p.NAME ILIKE '%' || #{keyword} || '%' OR p.CODE ILIKE '%' || #{keyword} || '%' )
AND p.STATUS = #{AllStatus}
AND p.STATUS IN ('ACTIVE','INACTIVE')
AND p.TYPE = #{AllType}
ORDER BY CASE p.STATUS WHEN 'ACTIVE' THEN 1 WHEN 'INACTIVE' THEN 2 WHEN 'DELETED' THEN 3 END, p.CREATED_AT DESC

SELECT COUNT(*)
FROM PARTNERS
WHERE CODE = #{code}
AND VISIBLE = TRUE

    AND ID != #{id}
